// Example DID Document (did:web method)
{
  "@context": [
    "https://www.w3.org/ns/did/v1",
    "https://w3id.org/security/suites/jws-2020/v1"
  ],
  "id": "did:web:verifiedid.contoso.com",
  "verificationMethod": [
    {
      "id": "did:web:verifiedid.contoso.com#key-1",
      "type": "JsonWebKey2020",
      "controller": "did:web:verifiedid.contoso.com",
      "publicKeyJwk": {
        "kty": "EC",
        "crv": "P-256",
        "x": "<base64url-encoded-x>",
        "y": "<base64url-encoded-y>"
      }
    }
  ],
  "authentication": ["did:web:verifiedid.contoso.com#key-1"],
  "assertionMethod": ["did:web:verifiedid.contoso.com#key-1"]
}

// Example Verifiable Credential payload
{
  "@context": [
    "https://www.w3.org/2018/credentials/v1",
    "https://verifiedid.did.msidentity.com/v1.0/contexts/VerifiedEmployee/v1"
  ],
  "type": ["VerifiableCredential", "VerifiedEmployee"],
  "issuer": "did:web:verifiedid.contoso.com",
  "issuanceDate": "2025-01-01T00:00:00Z",
  "expirationDate": "2026-01-01T00:00:00Z",
  "credentialSubject": {
    "id": "did:ion:EiDkZIcPW3...",
    "displayName": "John Smith",
    "jobTitle": "Software Engineer",
    "department": "Engineering",
    "employeeId": "E12345"
  },
  "proof": {
    "type": "JsonWebSignature2020",
    "verificationMethod": "did:web:verifiedid.contoso.com#key-1",
    "jws": "<base64url-compact-serialization>"
  }
}

// rules.json — defines the credential schema and data source
{
  "attestations": {
    "idTokenHints": [
      {
        "mapping": [
          { "outputClaim": "displayName", "required": true, "inputClaim": "$.displayName", "indexed": false },
          { "outputClaim": "jobTitle",    "required": true, "inputClaim": "$.jobTitle",    "indexed": false },
          { "outputClaim": "department",  "required": false, "inputClaim": "$.department",  "indexed": false }
        ],
        "required": true
      }
    ]
  },
  "validityInterval": 2592000,
  "vc": {
    "type": [ "VerifiedEmployee" ]
  }
}

# Create a presentation request — ask the user to present their VerifiedEmployee VC
presentation_payload = {
    'includeQRCode': True,
    'callback': {
        'url':   'https://app.contoso.com/api/vc/presentation-callback',
        'state': 'verify-session-99999',
        'headers': { 'api-key': '<your-callback-api-key>' }
    },
    'authority': 'did:web:verifiedid.contoso.com',
    'registration': { 'clientName': 'Contoso Partner Portal' },
    'requestedCredentials': [
        {
            'type':      'VerifiedEmployee',
            'purpose':   'We need to verify your employment status.',
            'acceptedIssuers': [
                'did:web:verifiedid.contoso.com'
            ],
            'configuration': {
                'validation': {
                    'allowRevoked':    False,
                    'validateLinkedDomain': True
                }
            }
        }
    ]
}

response = requests.post(
    f'https://verifiedid.did.msidentity.com/v1.0/<tenant-id>/verifiableCredentials/createPresentationRequest',
    headers={ 'Authorization': f'Bearer {access_token}', 'Content-Type': 'application/json' },
    json=presentation_payload
)

result = response.json()
print('QR Code URL:', result.get('qrCode'))
# User scans → Authenticator prompts → user approves → callback fires with claims

// Callback sent to your endpoint when issuance is complete
{
  "requestId": "9f6be8f5-7b0a-4e9f-852e-87c6f823baa2",
  "requestStatus": "issuance_successful",
  "state": "unique-session-state-12345",
  "subject": "did:ion:EiDkZIcPW3...",
  "issuanceDate": "2025-06-01T10:00:00Z",
  "expirationDate": "2026-06-01T10:00:00Z"
}

// Possible requestStatus values:
// 'request_retrieved'     — user scanned the QR code
// 'issuance_successful'   — credential issued to wallet
// 'issuance_error'        — issuance failed (check 'error' field)

// Callback sent when user successfully presents their VC
{
  "requestId": "a1b2c3d4-e5f6-7890-abcd-ef1234567890",
  "requestStatus": "presentation_verified",
  "state": "verify-session-99999",
  "subject": "did:ion:EiDkZIcPW3...",
  "verifiedCredentialsData": [
    {
      "issuer": "did:web:verifiedid.contoso.com",
      "type": ["VerifiableCredential", "VerifiedEmployee"],
      "claims": {
        "displayName": "John Smith",
        "jobTitle":    "Software Engineer",
        "department":  "Engineering"
      },
      "credentialState": {
        "revocationStatus": "VALID"
      },
      "issuanceDate":   "2025-01-01T00:00:00Z",
      "expirationDate": "2026-01-01T00:00:00Z"
    }
  ]
}
